function sanitizeMessages(msgs) {
  if (msgs.length === 0)
    return msgs;
  const merged = [];
  for (const msg of msgs) {
    if (msg.role === "system")
      continue;
    const last = merged[merged.length - 1];
    if (last && last.role === msg.role) {
      last.content += "\n\n" + msg.content;
    } else {
      merged.push({ ...msg });
    }
  }
  while (merged.length > 0 && merged[0].role !== "user") {
    merged.shift();
  }
  return merged;
}
