function mapActionTypeToCategory(actionType) {
  switch (actionType) {
    case "technical_audit":
    case "page_optimization":
      return "performance";
    case "schema_markup":
    case "link_building":
      return "seo";
    case "content_generation":
    case "content_refresh":
      return "content";
    default:
      return "seo";
  }
}
