async function notifyUser(userId, title2, message, env3) {
  let emailSent = false;
  let smsSent = false;
  try {
    const user = await env3.DB.prepare(
      "SELECT id, email, phone_number, notify_email, notify_sms FROM Users WHERE id = ?1"
    ).bind(userId).first();
    if (!user) {
      console.warn(`[Notifications] User ${userId} not found \u2014 skipping notification`);
      return { emailSent, smsSent };
    }
    if (user.notify_email === 1 && user.email) {
      emailSent = await sendUpdateEmail(user.email, title2, message, env3);
    }
    if (user.notify_sms === 1 && user.phone_number) {
      smsSent = await sendSmsUpdate(user.phone_number, message, env3);
    }
  } catch (err) {
    console.error("[Notifications] Master dispatcher error:", err instanceof Error ? err.message : err);
  }
  return { emailSent, smsSent };
}
