async function dispatchDigests(timeframe, env3) {
  const result = {
    timeframe,
    usersQueried: 0,
    emailsSent: 0,
    skipped: 0,
    errors: 0
  };
  try {
    const { results: users } = await env3.DB.prepare(
      `SELECT id, email FROM Users
       WHERE alert_frequency = ?1
         AND notify_email = 1
         AND status = 'active'`
    ).bind(timeframe).all();
    result.usersQueried = users?.length ?? 0;
    console.log(`[Newsletter] ${timeframe}: Found ${result.usersQueried} subscribed users`);
    if (!users || users.length === 0)
      return result;
    for (const user of users) {
      try {
        const digest = await generateDigestEmail(user.id, timeframe, env3);
        if (!digest) {
          result.skipped++;
          continue;
        }
        const sent = await sendDigestEmail(user.email, digest.subject, digest.html, env3);
        if (sent) {
          result.emailsSent++;
        } else {
          result.errors++;
        }
      } catch (err) {
        console.error(`[Newsletter] Error for user ${user.id}:`, err instanceof Error ? err.message : err);
        result.errors++;
      }
    }
  } catch (err) {
    console.error(`[Newsletter] Fatal error in ${timeframe} dispatch:`, err);
  }
  console.log(
    `[Newsletter] ${timeframe} complete \u2014 ${result.emailsSent} sent, ${result.skipped} skipped, ${result.errors} errors`
  );
  return result;
}
