async function handleGscSync(env3) {
  const result = {
    usersProcessed: 0,
    rowsUpserted: 0,
    errors: []
  };
  if (!env3.GOOGLE_CLIENT_ID || !env3.GOOGLE_CLIENT_SECRET) {
    console.log("[GSC Sync] Skipping \u2014 Google OAuth credentials not configured");
    return result;
  }
  const usersResult = await env3.DB.prepare(
    `SELECT id, gsc_refresh_token, gsc_property_url
     FROM Users
     WHERE gsc_refresh_token IS NOT NULL
       AND gsc_property_url IS NOT NULL
       AND gsc_property_url != ''`
  ).all();
  const users = usersResult.results || [];
  if (users.length === 0) {
    console.log("[GSC Sync] No users with GSC connected, skipping");
    return result;
  }
  console.log(`[GSC Sync] Starting sync for ${users.length} connected user(s)`);
  for (const user of users) {
    try {
      const rowsUpserted = await syncUserGscData(user, env3);
      result.usersProcessed++;
      result.rowsUpserted += rowsUpserted;
    } catch (err) {
      const msg = err instanceof Error ? err.message : "Unknown error";
      console.error(`[GSC Sync] Error for user ${user.id}: ${msg}`);
      result.errors.push(`${user.id}: ${msg}`);
    }
  }
  console.log(
    `[GSC Sync] Complete \u2014 ${result.usersProcessed} users, ${result.rowsUpserted} rows, ${result.errors.length} errors`
  );
  return result;
}
