async function handleGa4Sync(env3) {
  const result = {
    usersProcessed: 0,
    rowsUpserted: 0,
    errors: []
  };
  if (!env3.GOOGLE_CLIENT_ID || !env3.GOOGLE_CLIENT_SECRET) {
    console.log("[GA4 Sync] Skipping \u2014 Google OAuth credentials not configured");
    return result;
  }
  const usersResult = await env3.DB.prepare(
    `SELECT id, ga4_refresh_token, ga4_property_id
     FROM Users
     WHERE ga4_refresh_token IS NOT NULL
       AND ga4_property_id IS NOT NULL
       AND ga4_property_id != ''`
  ).all();
  const users = usersResult.results || [];
  if (users.length === 0) {
    console.log("[GA4 Sync] No users with GA4 connected, skipping");
    return result;
  }
  console.log(`[GA4 Sync] Starting sync for ${users.length} connected user(s)`);
  for (const user of users) {
    try {
      const rowsUpserted = await syncUserGa4Data(user, env3);
      result.usersProcessed++;
      result.rowsUpserted += rowsUpserted;
    } catch (err) {
      const msg = err instanceof Error ? err.message : "Unknown error";
      console.error(`[GA4 Sync] Error for user ${user.id}: ${msg}`);
      result.errors.push(`${user.id}: ${msg}`);
    }
  }
  console.log(
    `[GA4 Sync] Complete \u2014 ${result.usersProcessed} users, ${result.rowsUpserted} rows, ${result.errors.length} errors`
  );
  return result;
}
