function getConversionConfig(businessModel) {
  switch (businessModel) {
    case "e-commerce":
      return {
        label: "Add to Cart / Checkout",
        events: ["add_to_cart", "begin_checkout", "purchase"],
        description: "Tracks product add-to-cart actions and checkout funnel progression. A/B test winners are determined by the variant with higher add-to-cart rate.",
        primaryKpi: "add_to_cart_rate",
        secondaryKpis: [
          "checkout_rate",
          "revenue_per_session",
          "cart_abandonment_rate"
        ]
      };
    case "lead_gen":
      return {
        label: "Lead Capture",
        events: ["form_submit", "calendar_click", "email_capture", "phone_click"],
        description: "Tracks form submissions, calendar booking clicks, and email signups. A/B test winners are determined by the variant with higher lead capture rate.",
        primaryKpi: "lead_capture_rate",
        secondaryKpis: [
          "form_start_rate",
          "form_completion_rate",
          "calendar_booking_rate"
        ]
      };
    case "affiliate":
      return {
        label: "Affiliate Click-Through",
        events: ["affiliate_click", "outbound_click", "comparison_click"],
        description: "Tracks outbound clicks to affiliate partner domains. A/B test winners are determined by the variant with higher affiliate click-through rate.",
        primaryKpi: "affiliate_ctr",
        secondaryKpis: [
          "outbound_click_rate",
          "comparison_engagement",
          "revenue_per_click"
        ]
      };
    case "publisher":
      return {
        label: "Engagement Depth",
        events: ["scroll_75", "dwell_60s", "internal_click", "next_article"],
        description: "Tracks deep engagement: 75%+ scroll depth, 60s+ dwell time, and internal navigation. A/B test winners are determined by the variant with higher engagement depth rate.",
        primaryKpi: "engagement_depth_rate",
        secondaryKpis: [
          "avg_dwell_time",
          "scroll_depth",
          "pages_per_session",
          "bounce_rate"
        ]
      };
    default:
      return {
        label: "CTA Click",
        events: ["cta_click"],
        description: "Tracks generic CTA engagement. Set the business model in Brand Context for more precise conversion tracking.",
        primaryKpi: "cta_click_rate",
        secondaryKpis: ["scroll_depth", "dwell_time"]
      };
  }
}
