function mockPerplexityCheck(keyword, projectId) {
  let hash = 0;
  for (let i = 0; i < keyword.length; i++) {
    hash = (hash << 5) - hash + keyword.charCodeAt(i);
    hash |= 0;
  }
  const cited = Math.abs(hash) % 3 !== 0;
  const engines = [
    "Perplexity",
    "ChatGPT",
    "Gemini",
    "Claude",
    "CoPilot"
  ];
  const engine = engines[Math.abs(hash) % engines.length];
  return {
    keyword,
    cited,
    rank_position: cited ? Math.abs(hash) % 10 + 1 : null,
    citation_url: cited ? `https://${projectId === "proj_001" ? "swarme.io" : "example.com"}/${keyword.replace(/\s+/g, "-")}` : null,
    engine
  };
}
