app.post("/api/public/scanner", async (c) => {
  try {
    const { url } = await c.req.json();
    if (!url)
      return c.json({ success: false, error: "URL is required" }, 400);
    let headData = {
      title: "",
      description: "",
      canonical: "",
      ogImage: "",
      generator: "",
      schemaOrg: false,
      robots: "",
      viewport: "",
      charset: "",
      hreflang: []
    };
    let seoScore = 0;
    const issues = [];
    try {
      const resp = await fetch(url, {
        headers: { "User-Agent": "SwarmeBot/1.0 (+https://swarme.io)" },
        redirect: "follow"
      });
      const html = await resp.text();
      const titleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
      headData.title = titleMatch?.[1]?.trim() || "";
      const descMatch = html.match(/<meta[^>]+name=["']description["'][^>]+content=["']([^"']+)["']/i);
      headData.description = descMatch?.[1]?.trim() || "";
      const canonicalMatch = html.match(/<link[^>]+rel=["']canonical["'][^>]+href=["']([^"']+)["']/i);
      headData.canonical = canonicalMatch?.[1]?.trim() || "";
      const ogMatch = html.match(/<meta[^>]+property=["']og:image["'][^>]+content=["']([^"']+)["']/i);
      headData.ogImage = ogMatch?.[1]?.trim() || "";
      const robotsMatch = html.match(/<meta[^>]+name=["']robots["'][^>]+content=["']([^"']+)["']/i);
      headData.robots = robotsMatch?.[1]?.trim() || "";
      const viewportMatch = html.match(/<meta[^>]+name=["']viewport["'][^>]+content=["']([^"']+)["']/i);
      headData.viewport = viewportMatch?.[1]?.trim() || "";
      const charsetMatch = html.match(/<meta[^>]+charset=["']?([^"'\s>]+)/i);
      headData.charset = charsetMatch?.[1]?.trim() || "";
      headData.schemaOrg = html.includes("schema.org");
      if (headData.title)
        seoScore += 15;
      else
        issues.push("Missing <title> tag");
      if (headData.description)
        seoScore += 15;
      else
        issues.push("Missing meta description");
      if (headData.canonical)
        seoScore += 10;
      else
        issues.push("Missing canonical URL");
      if (headData.ogImage)
        seoScore += 10;
      else
        issues.push("Missing og:image");
      if (headData.viewport)
        seoScore += 10;
      else
        issues.push("Missing viewport meta tag");
      if (headData.charset)
        seoScore += 5;
      else
        issues.push("Missing charset declaration");
      if (headData.schemaOrg)
        seoScore += 10;
      else
        issues.push("No Schema.org markup detected");
      if (headData.robots)
        seoScore += 5;
      if (html.includes("<h1"))
        seoScore += 10;
      else
        issues.push("Missing <h1> heading");
      if (html.includes("alt="))
        seoScore += 10;
      else
        issues.push("Images may be missing alt attributes");
    } catch (fetchErr) {
      return c.json({ success: false, error: `Could not fetch URL: ${url}` }, 400);
    }
    return c.json({ success: true, result: { url, headData, seoScore, issues } });
  } catch (err) {
    return c.json({ success: false, error: "Scanner analysis failed" }, 500);
  }
});
